#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int* instructions = (int*) malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &instructions[i]);
        }
        int* stack = (int*) malloc(n * sizeof(int));
        int top = -1;
        int valid = 1;
        for (int i = 0; i < n; i++) {
            if (instructions[i] == 1) {
                stack[++top] = 1;
            } else {
                if (top == -1) {
                    valid = 0;
                    break;
                } else {
                    top--;
                }
            }
        }
        if (valid) {
            printf("Valid\n");
        } else {
            printf("Invalid\n");
        }
        free(instructions);
        free(stack);
    }
    return 0;
}

