const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const n = parseInt(readline());
    const instructions = readline().split(' ').map(Number);
    const stack = [];
    let valid = 1;
    for (let j = 0; j < n; j++) {
        if (instructions[j] === 1) {
            stack.push(1);
        } else {
            if (stack.length === 0) {
                valid = 0;
                break;
            } else {
                stack.pop();
            }
        }
    }
    if (valid) {
        console.log('Valid');
    } else {
        console.log('Invalid');
    }
}
